        }

        summary
    }

    pub fn entities_by_usage_frequency(
        &self,
        limit: Option<usize>,
    ) -> Vec<EntityFeedbackSummary> {
        let mut summaries = self.collect_all_summaries();
        summaries.sort_by(|left, right| {
