use super::*;

#[test]
fn feedback_input_defaults_note_kind_when_note_text_is_present() {
    let input = RuleFeedbackInput::new(
        FeedbackRating::Mixed,
        Some("  Needs refinement  ".to_string()),
        None,
        None,
