use feedback_io::*;

pub const FEEDBACK_SCHEMA_VERSION: u32 = 1;

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "kebab-case")]
pub enum FeedbackRating {
    Helpful,
    Mixed,
    NotHelpful,
}

impl FeedbackRating {
    pub const fn as_str(self) -> &'static str {
        match self {
            Self::Helpful => "helpful",
            Self::Mixed => "mixed",
            Self::NotHelpful => "not-helpful",
        }
    }
}

impl fmt::Display for FeedbackRating {
    fn fmt(
        &self,
        f: &mut fmt::Formatter<'_>,
    ) -> fmt::Result {
        f.write_str(self.as_str())
    }
}

impl FromStr for FeedbackRating {
    type Err = String;

    fn from_str(value: &str) -> Result<Self, Self::Err> {
        match value.trim().to_ascii_lowercase().as_str() {
            "helpful" => Ok(Self::Helpful),
            "mixed" => Ok(Self::Mixed),
            "not-helpful" => Ok(Self::NotHelpful),
            other => Err(format!(
                "invalid feedback rating '{other}', expected helpful, mixed, or not-helpful"
            )),
        }
    }
}

