#[derive(Debug, Default, Clone)]
pub struct EntityFeedbackCore {
    usage_events: Vec<EntityUsageEvent>,
    rating_events: Vec<EntityRatingEvent>,
}
const FEEDBACK_CORE_DIR: &str = "feedback-core";
