        Ok(Self {
            id: uuid::Uuid::new_v4().to_string(),
            schema_version: FEEDBACK_SCHEMA_VERSION,
            source,
            target,
            rating,
            note_text,
            note_kind,
            provenance,
            status: FeedbackStatus::New,
